#include <stdio.h>

int Count(int n) {
    int cnt = 0;
    int x = 1;
    while (1) {
        if (x > n) {
            break;
        }
        int y = 1;
        while (1) {
            if (x * y > n) {
                break;
            }
            cnt += 1;
            y *= 3;
        }
        x *= 2;
    }
    return cnt;
}

int Result(int l, int r) {
    if (l == 0) {
        return Count(r);
    }
    return Count(r) - Count(l - 1);
}

int main() {
    int l, r;
    scanf("%d %d", &l, &r);
    printf("%d\n", Result(l, r));
    return 0;
}
